{
  "name": "Laser Action Virtual Lab",
  "description": "An interactive educational platform for first-year engineering students to explore laser physics, including energy levels, population inversion, emission processes, and laser threshold conditions with an integrated AI tutor.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ModuleType {
  HOME = 'HOME',
  ENERGY_LEVELS = 'ENERGY_LEVELS',
  PUMPING = 'PUMPING',
  EMISSION = 'EMISSION',
  LASER_OUTPUT = 'LASER_OUTPUT',
  QUIZ = 'QUIZ',
  NUMERICAL = 'NUMERICAL'
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export interface EnergyLevelConfig {
  levels: number; // 2, 3, or 4
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getTutorResponse = async (
  message: string, 
  currentModule: string,
  history: { role: 'user' | 'model'; text: string }[]
) => {
  try {
    const model = 'gemini-3-flash-preview';
    const systemInstruction = `
      You are an expert Physics Tutor for the "Laser Action Virtual Lab".
      Your audience is first-year B.Tech engineering students.
      Current context: The student is on the ${currentModule} module.

      Guidelines:
      1. Explain concepts simply and clearly.
      2. Provide short, concise answers suitable for a "viva voce" (oral exam).
      3. Use small numerical examples to illustrate points.
      4. Avoid advanced mathematics unless requested.
      5. Focus on: population inversion, threshold conditions, metastable states, and Einstein coefficients.
      6. If they are in the 'ENERGY_LEVELS' module, explain why a 2-level system cannot achieve population inversion.
      7. Be encouraging and educational.
    `;

    const contents = history.map(h => ({
      role: h.role,
      parts: [{ text: h.text }]
    }));

    contents.push({
      role: 'user',
      parts: [{ text: message }]
    });

    const response = await ai.models.generateContent({
      model,
      contents: { parts: [{ text: message }] }, // Simple prompt for now, or use chat history if implemented
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a bit of trouble connecting to my knowledge base. Let's try that again!";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { getTutorResponse } from '../services/gemini';
import { ModuleType, ChatMessage } from '../types';

interface ChatbotProps {
  currentModule: ModuleType;
}

const Chatbot: React.FC<ChatbotProps> = ({ currentModule }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: `Hi! I'm your Laser Lab Tutor. How can I help you with the ${currentModule.replace('_', ' ')} concepts today?` }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    const response = await getTutorResponse(input, currentModule, messages);

    setMessages(prev => [...prev, { role: 'model', text: response || 'Sorry, I couldn\'t process that.' }]);
    setIsLoading(false);
  };

  return (
    <div className={`fixed bottom-4 right-4 z-50 transition-all duration-300 ${isOpen ? 'w-80 h-[500px]' : 'w-14 h-14'}`}>
      {!isOpen ? (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-14 h-14 bg-blue-600 text-white rounded-full shadow-lg flex items-center justify-center hover:bg-blue-700 transition-colors"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
          </svg>
        </button>
      ) : (
        <div className="bg-white rounded-lg shadow-2xl h-full flex flex-col overflow-hidden border border-gray-200">
          <div className="bg-blue-600 p-3 text-white flex justify-between items-center">
            <span className="font-bold">Laser Lab Assistant</span>
            <button onClick={() => setIsOpen(false)}>
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
              </svg>
            </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-3 space-y-3 bg-gray-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-2 rounded-lg text-sm ${
                  m.role === 'user' ? 'bg-blue-100 text-blue-900' : 'bg-white border text-gray-800'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border p-2 rounded-lg text-xs italic text-gray-400">Tutor is thinking...</div>
              </div>
            )}
          </div>

          <div className="p-2 border-t flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask a question..."
              className="flex-1 border rounded px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
            />
            <button 
              onClick={handleSend}
              className="bg-blue-600 text-white px-3 py-1 rounded text-sm hover:bg-blue-700"
            >
              Send
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default Chatbot;

import React, { useState, useEffect } from 'react';

const ModuleEnergyLevels: React.FC = () => {
  const [levelType, setLevelType] = useState<2 | 3 | 4>(3);
  const [electrons, setElectrons] = useState<{ id: number, level: number, x: number }[]>([]);

  // Initialize electrons
  useEffect(() => {
    const initialElectrons = Array.from({ length: 12 }, (_, i) => ({
      id: i,
      level: 0,
      x: 20 + Math.random() * 60
    }));
    setElectrons(initialElectrons);
  }, []);

  const moveRandomElectron = () => {
    setElectrons(prev => {
      const idx = Math.floor(Math.random() * prev.length);
      const newElectrons = [...prev];
      const currentLevel = newElectrons[idx].level;

      // Basic random transitions for animation effect
      let nextLevel = currentLevel;
      if (currentLevel === 0) {
        nextLevel = Math.floor(Math.random() * (levelType - 1)) + 1;
      } else {
        nextLevel = 0;
      }

      newElectrons[idx] = { ...newElectrons[idx], level: nextLevel };
      return newElectrons;
    });
  };

  useEffect(() => {
    const interval = setInterval(moveRandomElectron, 1500);
    return () => clearInterval(interval);
  }, [levelType]);

  const levels = Array.from({ length: levelType }, (_, i) => i);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex justify-between items-center bg-white p-4 rounded-xl shadow-sm">
        <h2 className="text-2xl font-bold text-gray-800">Atomic Energy Levels</h2>
        <div className="flex bg-gray-100 p-1 rounded-lg">
          {[2, 3, 4].map(n => (
            <button
              key={n}
              onClick={() => setLevelType(n as any)}
              className={`px-4 py-2 rounded-md transition-all ${
                levelType === n ? 'bg-blue-600 text-white shadow' : 'text-gray-600 hover:text-gray-900'
              }`}
            >
              {n}-Level
            </button>
          ))}
        </div>
      </div>

      <div className="grid md:grid-cols-3 gap-6">
        <div className="md:col-span-2 bg-gray-50 border rounded-xl h-[400px] relative p-8 flex flex-col justify-between">
          {levels.slice().reverse().map(lvl => (
            <div key={lvl} className="relative h-1 w-full bg-gray-300">
              <span className="absolute -top-6 left-0 text-xs font-mono font-bold text-gray-500">
                {lvl === 0 ? 'GROUND (E0)' : lvl === levelType - 1 ? 'EXCITED (Emax)' : `METASTABLE (E${lvl})`}
              </span>

              {electrons.filter(e => e.level === lvl).map(e => (
                <div
                  key={e.id}
                  className="absolute -top-3 w-6 h-6 bg-red-500 rounded-full border-2 border-white shadow-sm transition-all duration-1000 ease-in-out"
                  style={{ left: `${e.x}%` }}
                />
              ))}
            </div>
          ))}
        </div>

        <div className="space-y-4">
          <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-blue-900 mb-2">System Insights</h3>
            <p className="text-sm text-gray-600">
              {levelType === 2 && "In a 2-level system, population inversion is impossible because stimulated emission and absorption processes reach equilibrium at equal populations."}
              {levelType === 3 && "A 3-level system uses a metastable state to hold electrons longer, allowing for population inversion between E1 and E0."}
              {levelType === 4 && "A 4-level system is most efficient because the lower laser level (E1) is rapidly emptied, making population inversion easier to maintain."}
            </p>
          </div>

          <div className="bg-yellow-50 p-4 rounded-xl border border-yellow-100">
            <h4 className="font-bold text-yellow-800 text-sm mb-1 uppercase tracking-wider">Metastable State</h4>
            <p className="text-xs text-yellow-700 leading-relaxed">
              A state where electrons stay for a significantly longer time (approx 10⁻³ s) compared to excited states (10⁻⁸ s). This is CRITICAL for achieving population inversion.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ModuleEnergyLevels;

import React, { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const ModulePumping: React.FC = () => {
  const [pumpPower, setPumpPower] = useState(20);
  const [data, setData] = useState<{ time: number, N0: number, N1: number }[]>([]);
  const [time, setTime] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setTime(prev => prev + 1);
      setData(prev => {
        const last = prev.length > 0 ? prev[prev.length - 1] : { N0: 100, N1: 0 };

        // Simplified population dynamics
        // Rate of pumping proportional to pumpPower * N0
        // Rate of decay proportional to N1
        const pumpingRate = (pumpPower / 100) * last.N0;
        const decayRate = 0.1 * last.N1;

        const deltaN1 = pumpingRate - decayRate;
        const newN1 = Math.max(0, Math.min(100, last.N1 + deltaN1));
        const newN0 = 100 - newN1;

        const newData = [...prev, { time: time, N0: newN0, N1: newN1 }];
        return newData.slice(-50); // Keep last 50 points
      });
    }, 200);

    return () => clearInterval(interval);
  }, [time, pumpPower]);

  const isInversion = data.length > 0 && data[data.length - 1].N1 > data[data.length - 1].N0;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-6 rounded-xl shadow-sm space-y-4">
        <div className="flex justify-between items-center">
          <h2 className="text-2xl font-bold text-gray-800">Pumping & Population Inversion</h2>
          <div className={`px-4 py-1 rounded-full text-sm font-bold uppercase ${isInversion ? 'bg-green-100 text-green-700 animate-pulse' : 'bg-red-100 text-red-700'}`}>
            {isInversion ? 'Population Inversion Achieved!' : 'Normal Distribution'}
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-semibold text-gray-600 block">Pump Power (External Energy Input)</label>
          <input 
            type="range" 
            min="0" 
            max="100" 
            value={pumpPower} 
            onChange={(e) => setPumpPower(Number(e.target.value))}
            className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer accent-blue-600"
          />
          <div className="flex justify-between text-xs text-gray-400">
            <span>Minimum (0)</span>
            <span>Current: {pumpPower}%</span>
            <span>Maximum (100)</span>
          </div>
        </div>
      </div>

      <div className="grid md:grid-cols-3 gap-6">
        <div className="md:col-span-2 bg-white p-4 rounded-xl shadow-sm h-[350px]">
          <h3 className="text-sm font-bold text-gray-500 mb-4 uppercase">Population vs Time</h3>
          <ResponsiveContainer width="100%" height="90%">
            <LineChart data={data}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} />
              <XAxis dataKey="time" hide />
              <YAxis domain={[0, 100]} />
              <Tooltip />
              <Legend verticalAlign="top" height={36}/>
              <Line type="monotone" dataKey="N0" stroke="#3b82f6" name="Ground State (N0)" strokeWidth={2} dot={false} isAnimationActive={false} />
              <Line type="monotone" dataKey="N1" stroke="#ef4444" name="Metastable State (N1)" strokeWidth={2} dot={false} isAnimationActive={false} />
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="space-y-4">
          <div className="bg-blue-900 text-white p-5 rounded-xl shadow-lg h-full">
            <h3 className="font-bold mb-3 border-b border-blue-800 pb-2 text-blue-300 uppercase text-xs tracking-widest">Physics Explained</h3>
            <div className="space-y-4 text-sm">
              <p>
                <strong className="text-blue-200">Population Inversion:</strong> When the number of atoms in the higher energy level (N1) exceeds the number in the lower level (N0).
              </p>
              <p>
                <strong className="text-blue-200">The Condition:</strong> N1 &gt; N0. This is a non-equilibrium state required for light amplification.
              </p>
              <div className="bg-blue-800 p-3 rounded-lg border border-blue-700">
                <p className="text-xs font-mono">
                  Boltzman Dist: <br/>
                  N1/N0 = exp(-ΔE/kT)
                </p>
                <p className="mt-2 text-[10px] text-blue-400">
                  *Normally N1 is much less than N0. We need Pumping to reverse this!
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ModulePumping;

import React, { useState } from 'react';

const ModuleEmission: React.FC = () => {
