import React, { useState, useEffect } from 'react';

const AtomicStage: React.FC<{ onNext: () => void }> = ({ onNext }) => {
  const [levelType, setLevelType] = useState<2 | 3 | 4>(3);
  const [electrons, setElectrons] = useState<{ id: number; level: number; x: number }[]>([]);

  useEffect(() => {
    const initial = Array.from({ length: 15 }, (_, i) => ({
      id: i,
      level: 0,
      x: 20 + Math.random() * 60,
    }));
    setElectrons(initial);
  }, []);

  const moveElectrons = () => {
    setElectrons(prev => prev.map(e => {
      if (Math.random() > 0.8) {
        return { ...e, level: Math.floor(Math.random() * levelType) };
      }
      return e;
    }));
  };

  useEffect(() => {
    const timer = setInterval(moveElectrons, 2000);
    return () => clearInterval(timer);
  }, [levelType]);

  const levels = levelType === 2 ? [0, 1] : levelType === 3 ? [0, 1, 2] : [0, 1, 2, 3];
  const levelNames = ["Ground State (E₁)", "Metastable (E₂)", "Excited (E₃)", "Higher Excited (E₄)"];

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-12 animate-in fade-in duration-700">
      <div className="lg:col-span-2 space-y-8">
        <header className="flex justify-between items-end">
          <div className="space-y-1">
            <h2 className="text-3xl font-black text-slate-100">Atomic Energy Levels</h2>
            <p className="text-slate-500 text-sm">Observe how electrons occupy quantized levels.</p>
          </div>
          <div className="flex bg-slate-900 p-1 rounded-xl border border-slate-800">
            {[2, 3, 4].map(n => (
              <button
                key={n}
                onClick={() => setLevelType(n as any)}
                className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${
                  levelType === n ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
                }`}
              >
                {n}-Level System
              </button>
            ))}
