import React, { useState, useEffect } from 'react';

const PopulationStage: React.FC<{ onNext: () => void }> = ({ onNext }) => {
  const [pumpRate, setPumpRate] = useState(20);
  const [n0, setN0] = useState(100);
  const [n1, setN1] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setN1(prev => {
        const pump = (pumpRate / 100) * n0;
        const decay = 0.1 * prev;
        const next = Math.max(0, Math.min(100, prev + pump - decay));
        setN0(100 - next);
        return next;
      });
    }, 200);
    return () => clearInterval(timer);
  }, [pumpRate, n0]);

  const isInversion = n1 > n0;

  return (
    <div className="space-y-12 animate-in fade-in duration-700">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
        <div className="space-y-8">
          <header className="space-y-2">
            <h2 className="text-3xl font-black text-slate-100">Population Inversion</h2>
            <p className="text-slate-400">The "Active Medium" must be forced out of equilibrium.</p>
          </header>

          <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 space-y-8">
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <label className="text-xs font-bold uppercase tracking-widest text-slate-500">External Pump Source</label>
                <span className="text-rose-400 font-mono text-xl font-bold">{pumpRate}%</span>
              </div>
              <input 
                type="range" min="0" max="100" value={pumpRate}
                onChange={(e) => setPumpRate(parseInt(e.target.value))}
                className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-rose-600"
              />
            </div>

            <div className="flex gap-4 items-center justify-center p-6 bg-slate-950 rounded-2xl border border-slate-800">
               <div className="flex flex-col items-center gap-2">
                  <div className="w-16 bg-slate-800 rounded-lg relative overflow-hidden h-40">
                    <div className="absolute bottom-0 w-full bg-cyan-500 transition-all duration-300" style={{ height: `${n0}%` }}></div>
                  </div>
                  <span className="text-[10px] font-bold text-slate-500 uppercase">Ground (N₁)</span>
