               <div className="text-2xl font-black text-slate-800">VS</div>
               <div className="flex flex-col items-center gap-2">
                  <div className="w-16 bg-slate-800 rounded-lg relative overflow-hidden h-40">
                    <div className="absolute bottom-0 w-full bg-rose-500 transition-all duration-300 shadow-[0_0_20px_rgba(244,63,94,0.5)]" style={{ height: `${n1}%` }}></div>
                  </div>
                  <span className="text-[10px] font-bold text-slate-500 uppercase">Excited (N₂)</span>
               </div>
            </div>
          </div>
        </div>

        <div className="space-y-8">
          <div className={`p-8 rounded-3xl border-4 transition-all duration-500 h-full flex flex-col justify-between ${
            isInversion ? 'border-green-500 bg-green-500/5' : 'border-slate-800 bg-slate-900'
          }`}>
            <div className="space-y-6">
              <div className="flex items-center gap-3">
                <div className={`w-4 h-4 rounded-full ${isInversion ? 'bg-green-500 animate-ping' : 'bg-slate-700'}`}></div>
                <h3 className="text-2xl font-black">{isInversion ? 'INVERSION REACHED!' : 'Insufficient Pumping'}</h3>
              </div>

              <div className="bg-slate-950 p-6 rounded-2xl border border-slate-800 font-mono text-sm">
                <p className="text-slate-500 mb-2">// Thermodynamics Note</p>
                <p className="text-slate-300 italic">Normally N₂ = N₁e<sup>-ΔE/kT</sup></p>
                <p className="text-slate-500 mt-4 leading-relaxed">
                  In nature, N₂ is always less than N₁. To create a laser, we must cheat nature. 
                  When <strong>N₂ &gt; N₁</strong>, every photon that enters will cause stimulated emission more often than absorption.
                </p>
              </div>
            </div>

            <button 
              onClick={onNext}
              disabled={!isInversion}
              className={`w-full py-4 rounded-xl font-black transition-all ${
                isInversion 
                ? 'bg-green-500 text-slate-950 hover:bg-green-400 cursor-pointer shadow-xl' 
                : 'bg-slate-800 text-slate-600 cursor-not-allowed'
              }`}
            >
