          <h2 className="text-5xl font-black mb-4">Grade: {(score / QUESTIONS.length) * 100}%</h2>
          <p className="text-slate-400 mb-8">
            {score === QUESTIONS.length ? "Outstanding Engineer! You have mastered Laser Physics." : "Good progress. Review Phase 3 and 4 for better mastery."}
          </p>
          <div className="flex gap-4">
            <button onClick={onRestart} className="flex-1 bg-slate-100 text-slate-900 py-4 rounded-2xl font-black">Restart Course</button>
            <button onClick={() => window.print()} className="flex-1 border border-slate-700 py-4 rounded-2xl font-black hover:bg-slate-800">Print Result</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto space-y-12 animate-in slide-in-from-right duration-500">
      <header className="text-center space-y-2">
        <h2 className="text-3xl font-black">Performance Evaluation</h2>
        <p className="text-slate-500">Question {current + 1} of {QUESTIONS.length}</p>
      </header>

      <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 space-y-8">
        <h3 className="text-xl font-bold text-slate-100 leading-relaxed">{QUESTIONS[current].q}</h3>

        <div className="grid grid-cols-1 gap-4">
          {QUESTIONS[current].options.map((opt, i) => (
            <button
              key={i}
              onClick={() => setSelected(i)}
              className={`text-left p-5 rounded-2xl border-2 transition-all font-semibold ${
                selected === i ? 'bg-rose-600 border-rose-500 text-white' : 'bg-slate-950 border-slate-800 text-slate-400 hover:border-slate-700'
              }`}
            >
              {opt}
            </button>
          ))}
        </div>

        <button 
          onClick={handleNext}
          disabled={selected === null}
          className={`w-full py-5 rounded-2xl font-black text-xl transition-all ${
            selected !== null ? 'bg-slate-100 text-slate-950' : 'bg-slate-800 text-slate-600'
          }`}
        >
          {current === QUESTIONS.length - 1 ? 'Finish Assessment' : 'Continue'}
        </button>
      </div>
    </div>
  );
};

