import { GoogleGenAI } from "@google/genai";

// Fix: Always use named parameter for apiKey and use process.env.API_KEY directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getTutorResponse = async (
  message: string, 
  currentModule: string,
  history: { role: 'user' | 'model'; text: string }[]
) => {
  try {
    // Fix: Use gemini-3-pro-preview for complex reasoning and STEM tasks like physics tutoring
    const model = 'gemini-3-pro-preview';
    const systemInstruction = `
      You are an expert Physics Tutor for the "Laser Action Virtual Lab".
      Your audience is first-year B.Tech engineering students.
      Current context: The student is on the ${currentModule} module.

      Guidelines:
      1. Explain concepts simply and clearly.
      2. Provide short, concise answers suitable for a "viva voce" (oral exam).
      3. Use small numerical examples to illustrate points.
      4. Avoid advanced mathematics unless requested.
      5. Focus on: population inversion, threshold conditions, metastable states, and Einstein coefficients.
      6. If they are in the 'ATOMIC' or 'ENERGY_LEVELS' module, explain why a 2-level system cannot achieve population inversion.
      7. Be encouraging and educational.
    `;

    // Fix: Properly structure the contents with conversation history to provide context
    const contents = history.map(h => ({
      role: h.role,
      parts: [{ text: h.text }]
    }));

    contents.push({
      role: 'user',
      parts: [{ text: message }]
    });

    const response = await ai.models.generateContent({
      model,
      contents, // Fix: Send the full conversation history instead of just the last message
      config: {
        systemInstruction,
        temperature: 0.7,
      },
    });

    // Fix: Use .text property (not a method) to extract response content as per guidelines
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a bit of trouble connecting to my knowledge base. Let's try that again!";
  }
};

