import React, { useState, useEffect } from 'react';

const AtomicStage: React.FC<{ onNext: () => void }> = ({ onNext }) => {
  const [levelType, setLevelType] = useState<2 | 3 | 4>(3);
  const [electrons, setElectrons] = useState<{ id: number; level: number; x: number }[]>([]);

  useEffect(() => {
    setElectrons(Array.from({ length: 12 }, (_, i) => ({
      id: i,
      level: 0,
      x: 20 + Math.random() * 60,
    })));
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setElectrons(prev => prev.map(e => {
        if (Math.random() > 0.8) {
          // Transition: return to ground or jump to random excited state
          return { ...e, level: e.level > 0 ? 0 : Math.floor(Math.random() * (levelType - 1)) + 1 };
        }
        return e;
      }));
    }, 1500);
    return () => clearInterval(timer);
  }, [levelType]);

  const levels = Array.from({ length: levelType }, (_, i) => i);
  const labels = ["Ground State (E₁)", "Metastable (E₂)", "Excited (E₃)", "Upper Level (E₄)"];

  return (
    <div className="animate-stage space-y-10">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-3xl font-black text-white">Stage 2: Atomic Energy Levels</h2>
          <p className="text-slate-400 text-sm">Quantized energy states and the Metastable condition.</p>
        </div>
        <div className="flex bg-slate-900 p-1 rounded-xl border border-slate-800 shrink-0">
          {[2, 3, 4].map(n => (
            <button
              key={n}
              onClick={() => setLevelType(n as any)}
              className={`px-4 py-2 rounded-lg text-xs font-bold transition-all ${
                levelType === n ? 'bg-rose-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'
              }`}
            >
              {n}-Level
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-slate-900 border border-slate-800 rounded-3xl p-10 h-[450px] relative overflow-hidden">
          <svg className="w-full h-full" viewBox="0 0 400 300">
            {levels.reverse().map((lvl) => {
              const y = 250 - (lvl * 200 / (levelType - 1 || 1));
              return (
                <g key={lvl}>
                  <line x1="50" y1={y} x2="350" y2={y} stroke={lvl === 1 && levelType > 2 ? "#facc15" : "#334155"} strokeWidth="2" />
                  <text x="50" y={y - 10} fill="#64748b" className="text-[10px] font-bold uppercase tracking-wider">{labels[lvl]}</text>
                  {electrons.filter(e => e.level === lvl).map(e => (
                    <circle 
                      key={e.id}
                      cx={60 + (e.x * 2.8)}
                      cy={y}
                      r="6"
                      fill={lvl === 0 ? "#06b6d4" : "#f43f5e"}
                      className="transition-all duration-700 ease-in-out"
                    >
                      <animate attributeName="r" values="5;7;5" dur="2s" repeatCount="indefinite" />
                    </circle>
                  ))}
                </g>
              );
            })}
          </svg>
        </div>

        <div className="space-y-6">
          <section className="bg-slate-900 p-6 rounded-2xl border border-slate-800 space-y-4">
            <h3 className="text-rose-500 font-bold uppercase text-[10px] tracking-widest">Lab Notes</h3>
            <p className="text-xs text-slate-400 leading-relaxed">
              Electrons only exist at <strong className="text-slate-200">quantized levels</strong>. To make a laser, we need a special "Metastable State".
            </p>
            <div className="p-4 bg-slate-950 rounded-xl border border-slate-800">
              <p className="text-[10px] font-bold text-yellow-500 uppercase mb-1">Metastable State</p>
              <p className="text-[11px] text-slate-400 leading-tight">
                An energy level where electrons stay for a long time (~10⁻³ s) instead of falling instantly. This allows them to "accumulate".
              </p>
            </div>
            <p className="text-[11px] text-slate-500">
              {levelType === 2 
                ? "Note: In a 2-level system, you can only reach 50/50 population. Lasing is impossible." 
                : "Note: The 3rd and 4th levels act as reservoirs to store energy."}
            </p>
          </section>

          <button 
            onClick={onNext}
            className="w-full bg-white text-slate-950 font-black py-4 rounded-xl hover:bg-slate-200 transition-all active:scale-95 shadow-xl shadow-white/5"
          >
            Study Interactions →
          </button>
        </div>
      </div>
    </div>
  );
};

