import React, { useState, useEffect } from 'react';

const PopulationStage: React.FC<{ onNext: () => void }> = ({ onNext }) => {
  const [pump, setPump] = useState(20);
  const [n2, setN2] = useState(0); // Excited state population (0-100)

  // N1 (Ground state) is simply (100 - N2)
  const n1 = 100 - n2;

  useEffect(() => {
    const timer = setInterval(() => {
      setN2(prev => {
        const currentN1 = 100 - prev;
        const influx = (pump / 100) * currentN1;
        const decay = 0.08 * prev;
        const nextN2 = Math.max(0, Math.min(100, prev + influx - decay));
        return nextN2;
      });
    }, 100);
    return () => clearInterval(timer);
  }, [pump]);

  const isInverted = n2 > n1;

  return (
    <div className="animate-stage space-y-12">
      <header>
        <h2 className="text-3xl font-black text-white">Stage 4: Population Inversion</h2>
        <p className="text-slate-400 text-sm">Achieving the non-equilibrium state required for optical gain.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 space-y-10">
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <label className="text-xs font-bold uppercase tracking-widest text-slate-500">Pump Energy Source</label>
              <span className="text-rose-500 font-mono font-black text-xl">{pump}%</span>
            </div>
            <input 
              type="range" min="0" max="100" value={pump}
              onChange={(e) => setPump(parseInt(e.target.value))}
              className="w-full cursor-pointer"
            />
          </div>

          <div className="flex gap-6 items-end justify-center h-48 px-4">
            <div className="flex flex-col items-center gap-2 flex-1">
              <div className="w-full bg-slate-800 rounded-t-xl relative overflow-hidden h-full">
                <div 
                  className="absolute bottom-0 w-full bg-cyan-600 transition-all duration-300" 
                  style={{ height: `${n1}%` }}
                ></div>
              </div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Ground (N₁)</span>
            </div>
            <div className="flex flex-col items-center gap-2 flex-1">
              <div className="w-full bg-slate-800 rounded-t-xl relative overflow-hidden h-full">
                <div 
                  className="absolute bottom-0 w-full bg-rose-600 transition-all duration-300 shadow-[0_0_20px_rgba(225,29,72,0.6)]" 
                  style={{ height: `${n2}%` }}
                ></div>
              </div>
              <span className="text-[10px] font-bold text-slate-500 uppercase">Excited (N₂)</span>
            </div>
          </div>
        </div>

        <div className="space-y-8 flex flex-col justify-center">
          <div className={`p-8 rounded-3xl border-4 transition-all duration-500 ${
            isInverted ? 'border-green-500 bg-green-500/5 shadow-[0_0_30px_rgba(34,197,94,0.1)]' : 'border-slate-800 bg-slate-900 opacity-60'
          }`}>
            <h3 className="text-2xl font-black mb-4 flex items-center gap-3">
              <div className={`w-3 h-3 rounded-full ${isInverted ? 'bg-green-500 animate-pulse' : 'bg-slate-700'}`}></div>
              {isInverted ? 'Population Inversion!' : 'Normal Distribution'}
            </h3>
            <p className="text-sm text-slate-400 leading-relaxed mb-6">
              To create a laser, we must force more atoms into the excited state than the ground state. 
              When <strong className="text-white">N₂ &gt; N₁</strong>, stimulated emission becomes more likely than absorption.
            </p>
            <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 font-mono text-[11px] text-slate-400 leading-relaxed">
              <span className="text-rose-500 font-bold">PHYSICS RULE:</span><br/>
              N₂/N₁ = exp(-ΔE/kT) <br/>
              <span className="text-slate-600 italic">External pumping is used to overcome this equilibrium.</span>
            </div>
          </div>

          <button 
            disabled={!isInverted}
            onClick={onNext}
            className={`w-full py-4 rounded-xl font-black transition-all ${
              isInverted 
              ? 'bg-green-500 text-slate-950 shadow-xl shadow-green-900/20 hover:bg-green-400 active:scale-95' 
              : 'bg-slate-800 text-slate-600 cursor-not-allowed'
            }`}
          >
            {isInverted ? 'Enter Optical Cavity →' : 'Increase Pump Rate'}
          </button>
        </div>
      </div>
    </div>
  );
};

