import React, { useState, useEffect } from 'react';

const PopulationStage: React.FC<{ onNext: () => void }> = ({ onNext }) => {
  const [pump, setPump] = useState(20);
  const [n2, setN2] = useState(0); 

  // Thermodynamic model: N1 is the ground state population.
  // We assume a total population of 100 units.
  const n1 = 100 - n2;

  useEffect(() => {
    const timer = setInterval(() => {
      setN2(prev => {
        const currentN1 = 100 - prev;
        // Pumping increases N2, spontaneous decay decreases it.
        const pumpingRate = (pump / 100) * currentN1;
        const decayRate = 0.08 * prev;
        const nextN2 = Math.max(0, Math.min(100, prev + pumpingRate - decayRate));
        return nextN2;
      });
    }, 50);
    return () => clearInterval(timer);
  }, [pump]);

  const isInverted = n2 > n1;

  return (
    <div className="animate-stage space-y-12">
      <header>
        <h2 className="text-3xl font-black text-white">Stage 4: Population Inversion</h2>
        <p className="text-slate-400 text-sm">Achieving the non-equilibrium state required for optical gain.</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
        {/* Control Panel */}
        <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 space-y-10 flex flex-col justify-between">
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <label className="text-xs font-bold uppercase tracking-widest text-slate-500 block mb-1">Pump Energy Source</label>
                <p className="text-[10px] text-slate-400">Controls the rate of upward transitions</p>
              </div>
              <span className="text-rose-500 font-mono font-black text-2xl">{pump}%</span>
            </div>
            <div className="py-4">
              <input 
                type="range" 
                min="0" 
                max="100" 
                step="1"
                value={pump}
                onChange={(e) => setPump(parseInt(e.target.value))}
                className="w-full"
              />
            </div>
          </div>

          <div className="flex gap-10 items-end justify-center h-48 px-4 mt-8">
            <div className="flex flex-col items-center gap-4 flex-1 h-full">
              <div className="w-full bg-slate-950 rounded-t-2xl relative overflow-hidden h-full border border-slate-800">
                <div 
                  className="absolute bottom-0 w-full bg-cyan-600 transition-all duration-300" 
                  style={{ height: `${n1}%` }}
                ></div>
              </div>
              <div className="text-center">
                <span className="text-[11px] font-black text-slate-200 uppercase block">N₁</span>
                <span className="text-[9px] font-bold text-slate-500 uppercase">Ground</span>
              </div>
            </div>

            <div className="flex flex-col items-center gap-4 flex-1 h-full">
              <div className="w-full bg-slate-950 rounded-t-2xl relative overflow-hidden h-full border border-slate-800">
                <div 
                  className={`absolute bottom-0 w-full bg-rose-600 transition-all duration-300 ${n2 > 0 ? 'shadow-[0_0_30px_rgba(225,29,72,0.4)]' : ''}`} 
                  style={{ height: `${n2}%` }}
                ></div>
              </div>
              <div className="text-center">
                <span className="text-[11px] font-black text-slate-200 uppercase block">N₂</span>
                <span className="text-[9px] font-bold text-slate-500 uppercase">Excited</span>
              </div>
            </div>
          </div>
        </div>

        {/* Info Panel */}
        <div className="space-y-8 flex flex-col justify-center">
          <div className={`p-8 rounded-3xl border-4 transition-all duration-500 h-full flex flex-col justify-center ${
            isInverted ? 'border-green-500 bg-green-500/5 shadow-[0_0_40px_rgba(34,197,94,0.1)]' : 'border-slate-800 bg-slate-900 opacity-80'
          }`}>
            <h3 className="text-2xl font-black mb-4 flex items-center gap-3">
              <div className={`w-4 h-4 rounded-full ${isInverted ? 'bg-green-500 animate-pulse shadow-[0_0_10px_#22c55e]' : 'bg-slate-700'}`}></div>
              {isInverted ? 'Inversion Active!' : 'Normal State'}
            </h3>
            <p className="text-sm text-slate-400 leading-relaxed mb-6">
              In thermal equilibrium, <strong className="text-slate-200">N₁ &gt; N₂</strong>. To create a laser, we must force atoms into the excited state until <strong className="text-white">N₂ &gt; N₁</strong>.
              Only then can <span className="text-rose-400 font-bold uppercase">Stimulated Emission</span> dominate over absorption.
            </p>

            <div className="bg-slate-950 p-5 rounded-2xl border border-slate-800 font-mono text-[11px] text-slate-400 leading-relaxed space-y-2">
              <div className="flex justify-between">
                <span>Boltzmann Ratio:</span>
                <span className="text-slate-500 italic">e^(-ΔE/kT)</span>
              </div>
              <div className="h-[1px] bg-slate-800 w-full my-1"></div>
              <div className="flex justify-between items-center">
                <span>Gain Status:</span>
                <span className={isInverted ? 'text-green-500 font-bold' : 'text-slate-500 italic'}>
                  {isInverted ? 'OPTICAL GAIN > 1' : 'ATTENUATION'}
                </span>
              </div>
            </div>
          </div>

          <button 
            disabled={!isInverted}
            onClick={onNext}
            className={`w-full py-5 rounded-2xl font-black text-lg transition-all transform active:scale-95 ${
