              : 'bg-slate-800 text-slate-600 cursor-not-allowed grayscale'
            }`}
          >
            {isInverted ? 'Launch Optical Cavity →' : 'Increase Pumping for Inversion'}
          </button>
        </div>
      </div>
    </div>
  );
};

