          {stages.map((s, idx) => (
            <button
              key={s.id}
              onClick={() => setCurrentStage(s.id)}
              className={`text-left px-4 py-3 rounded-xl text-xs font-bold uppercase tracking-wider transition-all flex items-center gap-3 ${
                currentStage === s.id 
                ? 'bg-rose-600/10 text-rose-500 border border-rose-500/20 shadow-lg' 
                : 'text-slate-500 hover:text-slate-300 hover:bg-slate-800'
              }`}
            >
              <span className="opacity-50">{idx + 1}.</span>
              {s.label}
            </button>
          ))}
        </div>

        <div className="mt-auto pt-6 border-t border-slate-800 hidden md:block">
          <div className="p-4 bg-slate-800/50 rounded-xl border border-slate-700">
            <p className="text-[10px] font-bold text-slate-500 uppercase mb-2">Lab Status</p>
