export enum LabStage {
  INTRODUCTION = 'INTRO',
  THEORY_NOTES = 'THEORY',
  ATOMIC_STATES = 'ATOMIC',
  INTERACTIONS = 'INTERACTIONS',
  POPULATION = 'POPULATION',
  CAVITY = 'CAVITY',
  PRACTICE = 'PRACTICE',
  VIVA = 'VIVA'
}

export interface Observation {
  id: string;
  timestamp: number;
  params: Record<string, string | number>;
}

import React, { useState } from 'react';
import { LabStage, Observation } from './types';
import IntroStage from './components/IntroStage';
import AtomicStage from './components/AtomicStage';
import InteractionStage from './components/InteractionStage';
import PopulationStage from './components/PopulationStage';
import CavityStage from './components/CavityStage';
import PracticeStage from './components/PracticeStage';
import VivaStage from './components/VivaStage';
import TheoryNotes from './components/TheoryNotes';

const App: React.FC = () => {
  const [currentStage, setCurrentStage] = useState<LabStage>(LabStage.INTRODUCTION);
  const [observations, setObservations] = useState<Observation[]>([]);

  const stages = [
    { id: LabStage.INTRODUCTION, label: '01. Fundamentals' },
    { id: LabStage.THEORY_NOTES, label: '02. Theory Library' },
    { id: LabStage.ATOMIC_STATES, label: '03. Energy Levels' },
    { id: LabStage.INTERACTIONS, label: '04. Einstein Processes' },
    { id: LabStage.POPULATION, label: '05. Population Inversion' },
    { id: LabStage.CAVITY, label: '06. Optical Cavity' },
    { id: LabStage.PRACTICE, label: '07. Numerical Lab' },
    { id: LabStage.VIVA, label: '08. Final Evaluation' },
  ];

  const addObservation = (params: Record<string, string | number>) => {
    const newObs: Observation = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      params
    };
    setObservations(prev => [...prev, newObs]);
  };

  const renderStage = () => {
    switch (currentStage) {
      case LabStage.INTRODUCTION: return <IntroStage onNext={() => setCurrentStage(LabStage.THEORY_NOTES)} />;
      case LabStage.THEORY_NOTES: return <TheoryNotes onNext={() => setCurrentStage(LabStage.ATOMIC_STATES)} />;
      case LabStage.ATOMIC_STATES: return <AtomicStage onNext={() => setCurrentStage(LabStage.INTERACTIONS)} />;
      case LabStage.INTERACTIONS: return <InteractionStage onNext={() => setCurrentStage(LabStage.POPULATION)} />;
      case LabStage.POPULATION: return <PopulationStage onNext={() => setCurrentStage(LabStage.CAVITY)} onCapture={addObservation} />;
      case LabStage.CAVITY: return <CavityStage onNext={() => setCurrentStage(LabStage.PRACTICE)} onCapture={addObservation} />;
      case LabStage.PRACTICE: return <PracticeStage onNext={() => setCurrentStage(LabStage.VIVA)} />;
      case LabStage.VIVA: return <VivaStage onRestart={() => setCurrentStage(LabStage.INTRODUCTION)} observations={observations} />;
      default: return <IntroStage onNext={() => setCurrentStage(LabStage.THEORY_NOTES)} />;
    }
  };

  return (
