import React, { useState, useEffect } from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

const PopulationStage: React.FC<{ onNext: () => void, onCapture: (p: any) => void }> = ({ onNext, onCapture }) => {
  const [pump, setPump] = useState(20);
  const [history, setHistory] = useState<{ time: number, n1: number, n2: number }[]>([]);
  const [showManual, setShowManual] = useState(false);

  const n2 = (pump / 100) * 80;
  const n1 = 100 - n2;
  const isInverted = n2 > n1;

  useEffect(() => {
    const timer = setInterval(() => {
      setHistory(prev => {
        const nextTime = prev.length;
        const newData = [...prev, { time: nextTime, n1, n2 }];
        return newData.slice(-30);
      });
    }, 100);
    return () => clearInterval(timer);
  }, [n1, n2]);

  return (
    <div className="animate-stage space-y-12">
      <header className="space-y-6">
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <h2 className="text-3xl font-black text-white">Experiment 05: Population Dynamics</h2>
            <p className="text-slate-400 text-sm">Achieving and verifying the non-equilibrium state.</p>
          </div>
          <button 
            onClick={() => setShowManual(!showManual)}
            className="text-[10px] font-black uppercase text-rose-500 border border-rose-500/20 px-4 py-2 rounded-xl hover:bg-rose-500/10 transition-colors"
          >
            {showManual ? 'Hide Instructions' : 'Experiment Protocol'}
          </button>
        </div>

        {showManual && (
          <div className="bg-slate-900/50 p-8 rounded-[2rem] border border-slate-800 space-y-6 animate-fadeIn">
            <div>
              <h4 className="text-xs font-black uppercase text-rose-500 mb-2 tracking-widest">Aim</h4>
              <p className="text-sm text-slate-300">To demonstrate population inversion and determine the threshold pump power required for lasing.</p>
            </div>
            <div className="grid md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <h4 className="text-xs font-black uppercase text-slate-500 tracking-widest">Experiment Tasks</h4>
                <ul className="text-[11px] text-slate-400 space-y-2 list-disc list-inside">
                  <li>Record N1 and N2 at 0%, 25%, 50%, and 75% pump power.</li>
                  <li>Identify the intersection point on the graph (The Threshold).</li>
                  <li>Capture data for the Lab Report.</li>
                </ul>
              </div>
            </div>
          </div>
        )}
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-6 space-y-6">
           <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 flex flex-col justify-between h-[450px] shadow-xl">
             <div className="space-y-8">
                <div className="flex justify-between items-center">
                  <h4 className="text-xs font-black text-slate-500 uppercase tracking-widest">Pump Intensity Control</h4>
                  <span className="text-rose-500 font-mono font-black text-2xl">{pump}%</span>
                </div>
                <input type="range" min="0" max="100" value={pump} onChange={(e) => setPump(Number(e.target.value))} />
             </div>

             <div className="flex gap-10 items-end justify-center h-48 px-4">
                <div className="flex flex-col items-center gap-4 flex-1 h-full">
                  <div className="w-full bg-slate-950 rounded-t-2xl relative overflow-hidden h-full border border-slate-800">
                    <div className="absolute bottom-0 w-full bg-cyan-600 transition-all duration-300" style={{ height: `${n1}%` }}></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-500 uppercase">Ground (N₁)</span>
                </div>
                <div className="flex flex-col items-center gap-4 flex-1 h-full">
                  <div className="w-full bg-slate-950 rounded-t-2xl relative overflow-hidden h-full border border-slate-800">
                    <div className={`absolute bottom-0 w-full bg-rose-600 transition-all duration-300 ${isInverted ? 'shadow-[0_0_20px_#e11d48]' : ''}`} style={{ height: `${n2}%` }}></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-500 uppercase">Excited (N₂)</span>
                </div>
             </div>

             <button 
                onClick={() => onCapture({ Pump: pump, N1: Math.round(n1), N2: Math.round(n2), Inversion: isInverted ? 'Yes' : 'No' })}
                className="mt-6 text-[10px] font-black uppercase tracking-widest border border-slate-700 py-3 rounded-xl hover:bg-slate-800 transition-colors"
             >
                Capture Data Point
             </button>
           </div>
        </div>

        <div className="lg:col-span-6 space-y-6">
           <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 h-[450px] shadow-xl">
              <h4 className="text-[10px] font-black uppercase text-slate-500 mb-6 tracking-widest">Transient Population Graph (N vs t)</h4>
              <ResponsiveContainer width="100%" height="80%">
                 <LineChart data={history}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
                    <XAxis dataKey="time" hide />
