      <button 
        disabled={!isInverted}
        onClick={onNext}
        className={`w-full py-6 rounded-3xl font-black text-xl transition-all ${
          isInverted ? 'bg-white text-slate-950 hover:bg-slate-100 shadow-2xl' : 'bg-slate-800 text-slate-600 cursor-not-allowed'
        }`}
      >
        {isInverted ? 'Next: Optical Feedback Lab →' : 'Achieve Inversion to Continue'}
      </button>
    </div>
  );
};

