const VivaStage: React.FC<{ onRestart: () => void, observations: Observation[] }> = ({ onRestart, observations }) => {
  const [idx, setIdx] = useState(0);
  const [score, setScore] = useState(0);
  const [finished, setFinished] = useState(false);
  const [sel, setSel] = useState<number | null>(null);
  const [answers, setAnswers] = useState<boolean[]>([]);

  const handleNext = () => {
    const isCorrect = sel === QUESTIONS[idx].a;
    if (isCorrect) setScore(s => s + 1);
    setAnswers([...answers, isCorrect]);

    if (idx < QUESTIONS.length - 1) {
      setIdx(idx + 1);
      setSel(null);
    } else {
      setFinished(true);
    }
  };

  if (finished) {
    return (
      <div className="animate-stage space-y-12">
        <header className="text-center">
          <h2 className="text-4xl font-black text-white uppercase">Lab Experiment Final Report</h2>
