           <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 space-y-6">
              <h3 className="text-lg font-black text-white uppercase tracking-widest border-b border-slate-800 pb-4">Evaluation Summary</h3>
              {QUESTIONS.map((q, i) => (
                <div key={i} className="p-4 bg-slate-950 rounded-2xl border border-slate-800 space-y-2">
                   <div className="flex justify-between items-center">
                      <p className="text-xs font-bold text-slate-300">Q{i+1}: {answers[i] ? '✅' : '❌'}</p>
                   </div>
                   <p className="text-[10px] text-slate-500 italic">{q.e}</p>
                </div>
              ))}
           </div>

           <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 space-y-6">
