           <button onClick={onRestart} className="flex-1 bg-slate-800 text-slate-300 font-black py-6 rounded-[2rem] hover:bg-slate-700 transition-all border border-slate-700">Restart Laboratory Session</button>
        </div>

        {/* Print-only layout for the report */}
        <div className="print-only hidden p-10 font-serif">
           <h1 className="text-3xl font-black text-center mb-10 border-b-4 border-black pb-4 uppercase">Experiment Report: Laser Action Physics</h1>
