import { GoogleGenAI } from "@google/genai";

// Initialize the Google GenAI client with named parameter apiKey.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Interface for communicating with Gemini model to provide contextual tutoring.
 */
export const getGeminiResponse = async (userMessage: string) => {
  try {
    // Generate content directly using the model name and prompt.
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [{ parts: [{ text: userMessage }] }],
      config: {
        systemInstruction: "You are a world-class Physics tutor for the Laser Virtual Lab. Provide concise, clear, and mathematically accurate explanations about laser physics (energy levels, population inversion, Einstein coefficients, and optical cavities). Encourage students to experiment with the virtual lab controls.",
        temperature: 0.7,
      },
    });
    // Return extracted text property from response.
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { getGeminiResponse } from '../services/gemini';

const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{ role: 'user' | 'ai'; text: string }[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Maintain scroll at the latest message.
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const response = await getGeminiResponse(userMsg);
      setMessages(prev => [...prev, { role: 'ai', text: response || 'I encountered an issue processing your query.' }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', text: 'Error connecting to the AI tutor. Please check your network and try again.' }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="bg-slate-900 border border-slate-800 w-80 md:w-96 h-[500px] rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden animate-fadeIn">
          {/* Header */}
          <div className="bg-rose-600 p-5 flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
              <h3 className="text-white font-black uppercase text-[10px] tracking-widest">Physics AI Tutor</h3>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white hover:opacity-70 transition-opacity">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          {/* Chat Messages */}
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 bg-slate-950 scrollbar-hide">
            {messages.length === 0 && (
              <div className="text-slate-600 text-[9px] uppercase font-black text-center mt-20 tracking-[0.2em] leading-loose italic">
                Ready to help with your laser experiment questions...
              </div>
            )}
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-3xl text-[11px] leading-relaxed font-medium ${
                  m.role === 'user' 
                  ? 'bg-rose-600 text-white rounded-tr-none shadow-lg shadow-rose-900/20' 
                  : 'bg-slate-900 text-slate-300 rounded-tl-none border border-slate-800'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-slate-900 text-slate-500 p-4 rounded-3xl rounded-tl-none border border-slate-800 flex gap-1">
                  <div className="w-1.5 h-1.5 bg-rose-600 rounded-full animate-bounce"></div>
                  <div className="w-1.5 h-1.5 bg-rose-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1.5 h-1.5 bg-rose-600 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            )}
          </div>

          {/* User Input */}
          <div className="p-4 bg-slate-900 border-t border-slate-800 flex gap-2">
            <input 
              type="text" 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask a question..."
              className="flex-1 bg-slate-950 border border-slate-800 rounded-2xl px-4 py-3 text-white text-xs outline-none focus:border-rose-600 transition-colors placeholder:text-slate-700"
            />
            <button 
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className={`p-3 rounded-2xl transition-all ${
                isLoading || !input.trim() ? 'bg-slate-800 text-slate-600' : 'bg-rose-600 text-white hover:bg-rose-500 shadow-lg shadow-rose-900/30'
              }`}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M14 5l7 7m0 0l-7 7m7-7H3" /></svg>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-rose-600 w-16 h-16 rounded-[1.5rem] flex items-center justify-center shadow-2xl hover:scale-105 transition-all hover:bg-rose-500 group relative"
        >
          <div className="absolute inset-0 bg-rose-400 rounded-[1.5rem] animate-ping opacity-10"></div>
          <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M8 10h.01M12 10h.01M16 10h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
          </svg>
        </button>
      )}
    </div>
  );
};

export default Chatbot;

