                </div>
                <div className="px-4 py-6 bg-slate-950 rounded-3xl border border-slate-800 shadow-inner">
                  <input 
                    type="range" 
                    min="0" 
                    max="100" 
                    value={pump} 
                    onChange={(e) => setPump(Number(e.target.value))} 
                    className="w-full accent-rose-600 h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer"
                  />
                </div>
             </div>

             <div className="flex gap-12 items-end justify-center h-48 px-6">
                <div className="flex flex-col items-center gap-4 flex-1 h-full">
                  <div className="w-full bg-slate-950 rounded-t-3xl relative overflow-hidden h-full border border-slate-800 shadow-inner">
